class Solution:
    def smallestEquivalentString(self, s1: str, s2: str, baseStr: str) -> str:
        parent = {}
        rank = {}
        for i in range(26):
            parent[i] = i
            rank[i] = 0
        for c1, c2 in zip(s1, s2):
            find1 = self.find(ord(c1) - ord('a'))
            find2 = self.find(ord(c2) - ord('a'))
            if find1 != find2:
                self.union(find1, find2)
        res = []
        for c in baseStr:
            res.append(chr(self.find(ord(c) - ord('a')) + ord('a')))
        return ''.join(res)

    def find(self, x):
        if parent[x] != x:
            parent[x] = self.find(parent[x])
        return parent[x]

    def union(self, x, y):
        rootX = self.find(x)
        rootY = self.find(y)
        if rootX != rootY:
            if rank[rootX] > rank[rootY]:
                parent[rootY] = rootX
            else:
                parent[rootX] = rootY
                if rank[rootX] == rank[rootY]:
                    rank[rootY] += 1
